import fs from "node:fs";
import path from "node:path";
import process from "node:process";
import { fileURLToPath } from "node:url";

import { installFakeCodex, buildEnv } from "./fake-codex-fixture.mjs";
import { initGitRepo, makeTempDir, run } from "./helpers.mjs";
import { resolveStateDir } from "../plugins/codex/scripts/lib/state.mjs";

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const SCRIPT = path.join(ROOT, "plugins", "codex", "scripts", "codex-companion.mjs");

// Test 1: task-resume-candidate says no resumable task, but --resume-last resumes another session's thread
console.log("=== Test 1: --resume-last should respect session scoping ===\n");

const workspace = makeTempDir();
const binDir = makeTempDir();
installFakeCodex(binDir);
initGitRepo(workspace);
fs.writeFileSync(path.join(workspace, "README.md"), "hello\n");
run("git", ["add", "README.md"], { cwd: workspace });
run("git", ["commit", "-m", "init"], { cwd: workspace });

// Set up a state.json with a completed task from sess-other
const stateDir = resolveStateDir(workspace);
const jobsDir = path.join(stateDir, "jobs");
fs.mkdirSync(jobsDir, { recursive: true });

fs.writeFileSync(
  path.join(stateDir, "state.json"),
  `${JSON.stringify(
    {
      version: 1,
      config: { stopReviewGate: false },
      jobs: [
        {
          id: "task-other-session",
          status: "completed",
          title: "Codex Task",
          jobClass: "task",
          sessionId: "sess-other",
          threadId: "thr_other",
          summary: "Old rescue run",
          updatedAt: "2026-03-24T20:05:00.000Z"
        }
      ]
    },
    null,
    2
  )}\n`,
  "utf8"
);

// First verify task-resume-candidate says not available for sess-current
const candidateResult = run("node", [SCRIPT, "task-resume-candidate", "--json"], {
  cwd: workspace,
  env: {
    ...buildEnv(binDir),
    CODEX_COMPANION_SESSION_ID: "sess-current"
  }
});
console.log("task-resume-candidate --json result:");
console.log("  status:", candidateResult.status);
console.log("  stdout:", candidateResult.stdout.trim());
const candidatePayload = JSON.parse(candidateResult.stdout);
console.log("  available:", candidatePayload.available);
console.log("  candidate:", candidatePayload.candidate);

if (candidatePayload.available) {
  console.log("FAIL: task-resume-candidate should NOT be available for sess-current");
  process.exit(1);
}
console.log("PASS: task-resume-candidate correctly reports no resumable task for sess-current\n");

// Now run task --resume-last and see if it incorrectly resumes sess-other's thread
// The bug: resolveLatestTrackedTaskThread doesn't filter by session, so it picks up sess-other's thread
console.log("Running: task --resume-last 'follow up' with CODEX_COMPANION_SESSION_ID=sess-current");
const resumeResult = run("node", [SCRIPT, "task", "--resume-last", "follow up"], {
  cwd: workspace,
  env: {
    ...buildEnv(binDir),
    CODEX_COMPANION_SESSION_ID: "sess-current"
  }
});

console.log("  status:", resumeResult.status);
console.log("  stdout:", resumeResult.stdout.trim());
console.log("  stderr:", resumeResult.stderr.trim());

// Check the fake codex state to see which thread was used
const fakeStatePath = path.join(binDir, "fake-codex-state.json");
if (fs.existsSync(fakeStatePath)) {
  const fakeState = JSON.parse(fs.readFileSync(fakeStatePath, "utf8"));
  console.log("  lastTurnStart.threadId:", fakeState.lastTurnStart?.threadId);
  console.log("  lastTurnStart.resume:", fakeState.lastTurnStart?.resume);

  // BUG: If resumeLast was true and it used thr_other, that's the wrong thread
  if (fakeState.lastTurnStart?.resume && fakeState.lastTurnStart?.threadId === "thr_other") {
    console.log("\nBUG CONFIRMED: --resume-last resumed sess-other's thread (thr_other) even though CODEX_COMPANION_SESSION_ID=sess-current!");
    console.log("task-resume-candidate correctly said no resumable task exists for this session.");
    process.exit(2);
  }

  if (resumeResult.status !== 0 && resumeResult.stderr.includes("No previous Codex task thread was found")) {
    console.log("\nFIX WORKING: --resume-last correctly fails when no resumable task exists for the current session.");
  }
}

console.log("\nDone.");

