import fs from "node:fs";
import path from "node:path";
import process from "node:process";
import { fileURLToPath } from "node:url";

import { installFakeCodex, buildEnv } from "./fake-codex-fixture.mjs";
import { initGitRepo, makeTempDir, run } from "./helpers.mjs";
import { resolveStateDir } from "../plugins/codex/scripts/lib/state.mjs";

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const SCRIPT = path.join(ROOT, "plugins", "codex", "scripts", "codex-companion.mjs");

let passed = 0;
let failed = 0;

function assert(condition, message) {
  if (condition) {
    console.log(`  PASS: ${message}`);
    passed++;
  } else {
    console.log(`  FAIL: ${message}`);
    failed++;
  }
}

// Test 1: --resume-last should NOT resume a completed task from another session
console.log("=== Test 1: --resume-last should NOT resume a completed task from another session ===\n");

{
  const workspace = makeTempDir();
  const binDir = makeTempDir();
  installFakeCodex(binDir);
  initGitRepo(workspace);
  fs.writeFileSync(path.join(workspace, "README.md"), "hello\n");
  run("git", ["add", "README.md"], { cwd: workspace });
  run("git", ["commit", "-m", "init"], { cwd: workspace });

  const stateDir = resolveStateDir(workspace);
  const jobsDir = path.join(stateDir, "jobs");
  fs.mkdirSync(jobsDir, { recursive: true });

  fs.writeFileSync(
    path.join(stateDir, "state.json"),
    `${JSON.stringify(
      {
        version: 1,
        config: { stopReviewGate: false },
        jobs: [
          {
            id: "task-other-session",
            status: "completed",
            title: "Codex Task",
            jobClass: "task",
            sessionId: "sess-other",
            threadId: "thr_other",
            summary: "Old rescue run",
            updatedAt: "2026-03-24T20:05:00.000Z"
          }
        ]
      },
      null,
      2
    )}\n`,
    "utf8"
  );

  // Verify task-resume-candidate says not available for sess-current
  const candidateResult = run("node", [SCRIPT, "task-resume-candidate", "--json"], {
    cwd: workspace,
    env: {
      ...buildEnv(binDir),
      CODEX_COMPANION_SESSION_ID: "sess-current"
    }
  });
  const candidatePayload = JSON.parse(candidateResult.stdout);
  assert(!candidatePayload.available, "task-resume-candidate reports NOT available for sess-current");

  // Run task --resume-last - should fail with error about no previous thread
  const resumeResult = run("node", [SCRIPT, "task", "--resume-last", "follow up"], {
    cwd: workspace,
    env: {
      ...buildEnv(binDir),
      CODEX_COMPANION_SESSION_ID: "sess-current"
    }
  });

  // Currently this is the BUG: it tries to resume thr_other from sess-other
  console.log(`  resumeResult.status: ${resumeResult.status}`);
  console.log(`  resumeResult.stderr: ${resumeResult.stderr.trim()}`);

  // After fix, it should fail with "No previous Codex task thread was found"
  const hasCorrectError = resumeResult.status !== 0 &&
    resumeResult.stderr.includes("No previous Codex task thread was found");
  const isBugActive = resumeResult.stderr.includes("Resuming thread thr_other");

  if (isBugActive) {
    console.log("  BUG: --resume-last is trying to resume sess-other's thread thr_other!");
  }
  assert(!isBugActive, "--resume-last does NOT resume sess-other's thread");
  assert(hasCorrectError, "--resume-last fails with 'No previous Codex task thread was found'");
}

console.log("");

// Test 2: A running task from another session should NOT block --resume-last for the current session
console.log("=== Test 2: Running task from another session should NOT block --resume-last ===\n");

{
  const workspace = makeTempDir();
  const binDir = makeTempDir();
  installFakeCodex(binDir);
  initGitRepo(workspace);
  fs.writeFileSync(path.join(workspace, "README.md"), "hello\n");
  run("git", ["add", "README.md"], { cwd: workspace });
  run("git", ["commit", "-m", "init"], { cwd: workspace });

  const stateDir = resolveStateDir(workspace);
