        jobs: [
          {
            id: "task-other-running",
            status: "running",
            title: "Codex Task",
            jobClass: "task",
            sessionId: "sess-other",
            threadId: "thr_other_running",
            summary: "Still running in another session",
            updatedAt: "2026-03-24T20:05:00.000Z"
          }
        ]
      },
      null,
      2
    )}\n`,
    "utf8"
  );

  // Run task --resume-last from sess-current - should NOT be blocked by sess-other's running task
  const resumeResult = run("node", [SCRIPT, "task", "--resume-last", "follow up"], {
    cwd: workspace,
    env: {
      ...buildEnv(binDir),
      CODEX_COMPANION_SESSION_ID: "sess-current"
    }
  });

  console.log(`  resumeResult.status: ${resumeResult.status}`);
  console.log(`  resumeResult.stderr: ${resumeResult.stderr.trim()}`);

  // Currently this is the BUG: it says "Task task-other-running is still running"
  const isBlockedByOtherSession = resumeResult.stderr.includes("is still running");
  const hasCorrectError = resumeResult.status !== 0 &&
    resumeResult.stderr.includes("No previous Codex task thread was found");

  if (isBlockedByOtherSession) {
    console.log("  BUG: --resume-last blocked by sess-other's running task!");
  }
  assert(!isBlockedByOtherSession, "--resume-last is NOT blocked by another session's running task");
  assert(hasCorrectError, "--resume-last fails with correct 'not found' error");
}

console.log(`\n${passed} passed, ${failed} failed`);
if (failed > 0) {
  process.exit(1);
}

