  const firstRun = run("node", [SCRIPT, "task", "initial task"], {
    cwd: workspace,
    env: {
      ...buildEnv(binDir),
      CODEX_COMPANION_SESSION_ID: "sess-current"
    }
  });
  assert(firstRun.status === 0, "First task runs successfully with session ID");

  // --resume-last should find the current session's job
  const resumeResult = run("node", [SCRIPT, "task", "--resume-last", "follow up"], {
    cwd: workspace,
    env: {
      ...buildEnv(binDir),
      CODEX_COMPANION_SESSION_ID: "sess-current"
    }
  });
  assert(resumeResult.status === 0, "--resume-last works with session ID for own jobs");
  assert(resumeResult.stdout.includes("Resumed"), "Output contains 'Resumed'");
}

console.log(`\n${passed} passed, ${failed} failed`);
if (failed > 0) {
  process.exit(1);
}

